/* ============================================================================
   Marriage Map — perspectives (metrics), the history-of-marriage timeline,
   global trends, and the time axis.
   ----------------------------------------------------------------------------
   window.METRICS       — the map "perspectives": each colours the world by one
                          dimension of marriage. kind drives the colour scale:
                            'gyr'  green→yellow→red (low→high; high is "worse")
                            'age'  red→yellow→green (low→high; low is "worse")
                            'warm'|'blue'|'teal'|'purple'  sequential (dim→bright)
                            'cat'  categorical (uses .cats colours)
   window.EVENT_CATS    — categories for the history timeline (colour per kind).
   window.MARRIAGE_EVENTS — milestones in the history of marriage (seed; the full
                          set is research-assembled). year negative = BCE.
   window.TRENDS        — global time-series (fertility, age at marriage, divorce…).
   window.TIME_SLICES   — the timeline's anchors (3000 BCE → today).

   Country data lives in data/marriage-data.js (window.COUNTRY_DATA[ISO2]).
   Figures are the latest reliable estimates; sources in About.
   ========================================================================== */
'use strict';

window.METRICS = {
  divorce:      { field: 'divorceRate', label: 'Divorce rate', short: 'Divorce', unit: '%', kind: 'gyr', domain: [5, 55], fmt: 'pct0', good: 'low', desc: '% of marriages that end in divorce' },
  fertility:    { field: 'fertility', label: 'Children per woman', short: 'Children', unit: '', kind: 'warm', domain: [1, 6], fmt: 'dec1', desc: 'Total fertility rate — average children per woman' },
  married:      { field: 'pctMarried', label: 'Adults married', short: 'Married', unit: '%', kind: 'blue', domain: [20, 65], fmt: 'pct0', desc: 'Share of adults (15+) currently married' },
  marriageRate: { field: 'crudeMarriageRate', label: 'Marriages / 1,000', short: 'Marriage rate', unit: '', kind: 'teal', domain: [2, 11], fmt: 'dec1', desc: 'Marriages per 1,000 people per year' },
  ageFirst:     { field: 'medianAgeFirstMarriageFemale', label: 'Age at first marriage (women)', short: 'Age at marriage', unit: ' yrs', kind: 'purple', domain: [18, 34], fmt: 'dec1', desc: 'Median age at which women first marry' },
  minAge:       { field: 'minAgeFemale', label: 'Min. legal age (women)', short: 'Min. age', unit: ' yrs', kind: 'age', domain: [14, 21], fmt: 'int', good: 'high', desc: 'General minimum legal marriage age for women (no exceptions)' },
  childMarriage:{ field: 'childMarriagePct', label: 'Married before 18', short: 'Child marriage', unit: '%', kind: 'gyr', domain: [0, 40], fmt: 'pct0', good: 'low', desc: '% of women married before age 18' },
  avgMarriages: { field: 'avgMarriages', label: 'Marriages per person', short: 'Avg. marriages', unit: '', kind: 'warm', domain: [1, 2], fmt: 'dec1', desc: 'Average lifetime number of marriages' },
  polygamy:     { field: 'polygamy', label: 'Polygamy', short: 'Polygamy', kind: 'cat', desc: 'Legal status of polygamous marriage',
    cats: { banned: { label: 'Banned', color: '#2fa84f' }, partial: { label: 'Some groups / regions', color: '#e0a92f' }, legal: { label: 'Legal', color: '#c0392b' } } },
  sameSex:      { field: 'sameSexMarriage', label: 'Same-sex marriage', short: 'Same-sex', kind: 'cat', desc: 'Legal recognition of same-sex marriage',
    cats: { legal: { label: 'Legal', color: '#2f6fe0' }, civil: { label: 'Civil union only', color: '#7aa8e0' }, banned: { label: 'Not recognised', color: '#6f7c93' } } },
};
window.METRIC_ORDER = ['divorce', 'fertility', 'married', 'marriageRate', 'ageFirst', 'minAge', 'childMarriage', 'avgMarriages', 'polygamy', 'sameSex'];

window.EVENT_CATS = {
  ancient:   { label: 'Ancient law',        color: '#b08a3a' },
  legal:     { label: 'Civil & legal',      color: '#2f6fe0' },
  religious: { label: 'Religious',          color: '#9b6fd0' },
  rights:    { label: 'Spousal rights',     color: '#e0568f' },
  age:       { label: 'Marriage age',       color: '#e0962f' },
  divorce:   { label: 'Divorce',            color: '#c0392b' },
  polygamy:  { label: 'Polygamy',           color: '#7d3c2e' },
  samesex:   { label: 'Same-sex marriage',  color: '#2fa8a0' },
  custom:    { label: 'Custom & society',   color: '#5e8bef' },
};

window.TIME_SLICES = [
  { id: '-3000', label: '3000 BCE', era: 'ancient' },
  { id: '-2100', label: '2100 BCE', era: 'ancient' },
  { id: '-1754', label: '1750 BCE', era: 'ancient' },
  { id: '-1000', label: '1000 BCE', era: 'ancient' },
  { id: '-200',  label: '200 BCE',  era: 'ancient' },
  { id: '1',     label: '1 CE',     era: 'classical' },
  { id: '620',   label: '620 CE',   era: 'classical' },
  { id: '1184',  label: '1184',     era: 'medieval' },
  { id: '1563',  label: '1563',     era: 'medieval' },
  { id: '1700',  label: '1700',     era: 'earlymodern' },
  { id: '1800',  label: '1800',     era: 'earlymodern' },
  { id: '1850',  label: '1850',     era: 'modern' },
  { id: '1900',  label: '1900',     era: 'modern' },
  { id: '1920',  label: '1920',     era: 'modern' },
  { id: '1950',  label: '1950',     era: 'modern' },
  { id: '1970',  label: '1970',     era: 'contemporary' },
  { id: '1990',  label: '1990',     era: 'contemporary' },
  { id: '2010',  label: '2010',     era: 'contemporary' },
  { id: '2025',  label: 'today',    era: 'contemporary' },
];

window.MARRIAGE_EVENTS = [
  { id: "bride-price-origins", year: -2600, title: "Bride-Price Recorded in Sumerian Texts", place: "Ur, Sumer", iso: "IQ", lat: 30.9625, lng: 46.1033, cat: "custom", blurb: "Sumerian administrative records from Ur III (~2600–2100 BCE) contain the earliest documented bride-price payments (terhatum) — silver or goods paid by the groom's family to the bride's — establishing a formal economic foundation for marriage that appears across virtually all subsequent ancient legal systems.", src: ["Roth, M.T., Law Collections from Mesopotamia (1997)","van der Toorn, K., From Her Cradle to Her Grave (1994)"] },
  { id: "ancient-dowry-origin", year: -2500, title: "First Evidence of Formal Dowry Practice", place: "Lagash, Sumer", iso: "IQ", lat: 31.5892, lng: 46.5223, cat: "custom", blurb: "Administrative tablets from Lagash (~2500 BCE) record a father transferring property — including land, livestock, and household goods — to his daughter at marriage, constituting the earliest documented dowry system. This practice spread from Mesopotamia to Greece, Rome, India, and China, shaping marriage economics globally.", src: ["Gelb, I.J., Steinkeller, P., Whiting, R.M., Earliest Land Tenure Systems in the Near East (1991)","Hughes, D.O., 'From Brideprice to Dowry', Journal of Family History (1978)"] },
  { id: "mesopotamian-marriage-contract", year: -2350, title: "Earliest Marriage Contract Tablets", place: "Nippur, Sumer", iso: "IQ", lat: 32.1267, lng: 45.2314, cat: "legal", blurb: "Cuneiform clay tablets from Nippur (~2350 BCE) record the earliest known written marriage contracts, stipulating bride-price, dowry, and conditions of the union. These tablets show marriage was already a formal legal institution in Sumerian city-states.", src: ["Greengus, S., 'Old Babylonian Marriage Ceremonies', Journal of Near Eastern Studies (1966)","van der Toorn, K., From Her Cradle to Her Grave (1994)"] },
  { id: "ur-nammu", year: -2100, title: "Code of Ur-Nammu", place: "Ur, Sumer", iso: "IQ", lat: 30.96, lng: 46.1, cat: "ancient", blurb: "The oldest surviving law code already regulates marriage, dowry and divorce — among the first written marriage law anywhere.", src: ["Code of Ur-Nammu"] },
  { id: "ur-nammu-marriage-law", year: -2100, title: "First Written Marriage Laws", place: "Ur, Sumer", iso: "IQ", lat: 30.9625, lng: 46.1033, cat: "legal", blurb: "The Code of Ur-Nammu (~2100 BCE), the oldest surviving law code, includes provisions governing marriage, divorce, and bride-price — the earliest written marriage legislation in history. It established that a man who divorces his first wife must pay her one mina of silver.", src: ["Roth, M.T., Law Collections from Mesopotamia (1997)","Finegan, J., Archaeological History of the Ancient Middle East (1979)"] },
  { id: "ur-nammu-divorce-protection", year: -2100, title: "First Written Law Protects Wives", place: "Ur, Mesopotamia", iso: "IQ", lat: 30.962, lng: 46.103, cat: "ancient", blurb: "The Code of Ur-Nammu (~2100 BCE), the world's oldest surviving law code, included provisions requiring compensation for a woman in cases of divorce and penalties for false accusations of adultery against a wife. It is the earliest written evidence of legally recognised protections for married women.", src: ["https://en.wikipedia.org/wiki/Code_of_Ur-Nammu","https://www.worldhistory.org/Code_of_Ur-Nammu/"] },
  { id: "ancient-egyptian-marriage", year: -2000, title: "Egyptian Marriage Without State Religion", place: "Memphis, Egypt", iso: "EG", lat: 29.8521, lng: 31.251, cat: "ancient", blurb: "Ancient Egyptian marriage (~2000 BCE onward) was a purely civil and social contract — uniquely secular for the ancient world — requiring no priest, temple, or state official. A couple simply set up a household together, often formalised by a written property agreement (senit).", src: ["Tyldesley, J., Daughters of Isis (1994)","Pestman, P.W., Marriage and Matrimonial Property in Ancient Egypt (1961)"] },
  { id: "hammurabi", year: -1754, title: "Hammurabi codifies marriage", place: "Babylon", iso: "IQ", lat: 32.54, lng: 44.42, cat: "ancient", blurb: "Hammurabi’s Code makes marriage a binding written contract, sets dowry and bride-price rules, and gives women limited grounds for divorce.", src: ["Code of Hammurabi"] },
  { id: "hammurabi-polygamy", year: -1754, title: "Hammurabi Regulates Polygamy", place: "Babylon", iso: "IQ", lat: 32.5422, lng: 44.4218, cat: "polygamy", blurb: "The Code of Hammurabi (~1754 BCE) is the earliest legal code to formally regulate polygamy: a man could take a second wife only if his first was barren, and even then the first wife retained seniority and specific economic protections. This represents the first state-imposed hierarchy among co-wives.", src: ["Roth, M.T., Law Collections from Mesopotamia (1997)","Stol, M., Women in the Ancient Near East (2016)"] },
  { id: "hammurabi-wife-divorce-rights", year: -1754, title: "Wife May Divorce Degrading Husband", place: "Babylon, Mesopotamia", iso: "IQ", lat: 32.542, lng: 44.421, cat: "ancient", blurb: "The Code of Hammurabi (~1754 BCE) granted a wife the right to initiate divorce and retain her dowry, property, and children if she could prove her husband 'degraded' her — an early, if limited, legal recognition of a woman's right to exit an abusive marriage. The code also required a divorcing husband with children to leave the wife a field or property for child-rearing.", src: ["https://africame.factsanddetails.com/article/entry-1012.html","https://courses.lumenlearning.com/suny-hccc-worldcivilization/chapter/hammurabis-code/"] },
  { id: "hammurabi-marriage-age", year: -1754, title: "Hammurabi sets minimum marriage age", place: "Babylon (modern Iraq)", iso: "IQ", lat: 32.5, lng: 44.4, cat: "ancient", blurb: "The Code of Hammurabi (~1754 BCE) stipulated that a girl could not be given in marriage before puberty, making it one of the earliest recorded legal constraints on marriage age. Contracts for underage girls required a waiting clause until she came of age.", src: ["Code of Hammurabi §§ 155–156","Westbrook, R. (1988). Old Babylonian Marriage Law."] },
  { id: "hammurabi-divorce-babylon", year: -1754, title: "Hammurabi Code codifies divorce rights", place: "Babylon, Mesopotamia", iso: "IQ", lat: 32.5355, lng: 44.4209, cat: "divorce", blurb: "The Code of Hammurabi (c. 1754 BCE) is the earliest surviving legal code to explicitly regulate divorce: a husband could divorce his wife by declaring \"she is not my wife\" and paying a settlement, and a wife could petition for divorce if her husband was cruel or negligent. These provisions mark the first written no-fault and fault-based divorce rules in recorded law.", src: ["Code of Hammurabi §§137–142","Martha T. Roth, Law Collections from Mesopotamia (1997)"] },
  { id: "hammurabi-marriage-contract", year: -1753, title: "Written marriage contract required by law", place: "Babylon, Mesopotamia", iso: "IQ", lat: 32.54, lng: 44.42, cat: "legal", blurb: "The Code of Hammurabi (~1753 BCE) decreed that any marriage without a written contract was legally invalid — the earliest known state mandate for documented marriage. Tablets recorded the parties' names, witnesses, dowry terms, and date.", src: ["https://grokipedia.com/page/mesopotamian_marriage_law","https://en.wikipedia.org/wiki/Code_of_Hammurabi"] },
  { id: "mesopotamia-polygamy-code", year: -1750, title: "Hammurabi codifies polygamous marriage", place: "Babylon, Mesopotamia", iso: "IQ", lat: 32.54, lng: 44.42, cat: "ancient", blurb: "The Code of Hammurabi formalised polygyny in Babylonian law, permitting a man to take a second wife if the first was ill or infertile. This is among the earliest written legal frameworks acknowledging plural marriage.", src: ["Hammurabi Code §§ 144–147","Westbrook, R. — Old Babylonian Marriage Law (1988)"] },
  { id: "egypt-contracts", year: -1500, title: "Egyptian marriage contracts", place: "Egypt", iso: "EG", lat: 26, lng: 32, cat: "ancient", blurb: "Marriage in ancient Egypt was a private property arrangement; women could own property and initiate divorce — strikingly equal for the era.", src: ["Egyptian papyri"] },
  { id: "vedic-vivah-ritual", year: -1500, title: "Vedic Wedding Rite Codified", place: "Indus-Ganges Plain, India", iso: "IN", lat: 27, lng: 77, cat: "religious", blurb: "The Rigveda (~1500 BCE) contains the earliest textual description of a sacred marriage ceremony (vivah), including the saptapadi — seven steps around the sacred fire — making this the oldest continuously practised religious marriage ritual in the world.", src: ["Olivelle, P., Dharmasutras (1999)","Kane, P.V., History of Dharmasastra vol. II (1941)"] },
  { id: "hindu-vivaha-rigveda", year: -1500, title: "Vivaha rites codified in Rigveda", place: "Indus-Gangetic Plain, South Asia", iso: "IN", lat: 25, lng: 77, cat: "religious", blurb: "The Rigveda's hymns (c. 1500–1200 BCE) prescribe the seven steps (saptapadi) around a sacred fire and the exchange of vows that define Hindu vivaha to this day. This is the earliest textual codification of a religiously sanctioned marriage ceremony.", src: ["Rigveda X.85 (Surya's wedding hymn)","Kane, P.V., History of Dharmaśāstra, vol. 2"] },
  { id: "assyrian-marriage-law", year: -1450, title: "Middle Assyrian Laws on Marriage", place: "Ashur (Qal'at Sherqat)", iso: "IQ", lat: 35.4558, lng: 43.2597, cat: "legal", blurb: "The Middle Assyrian Laws (~1450 BCE) are the first texts to mandate veiling of wives and concubines in public — distinguishing married women from prostitutes by law — and specify severe penalties for adultery, making them the earliest legal regulation of marital status as visible public identity.", src: ["Roth, M.T., Law Collections from Mesopotamia (1997)","Westbrook, R., ed., A History of Ancient Near Eastern Law (2003)"] },
  { id: "zhou-china-six-rites", year: -1046, title: "Zhou Dynasty Formalises Six Marriage Rites", place: "Hao, Zhou Kingdom (near Xi'an)", iso: "CN", lat: 34.2658, lng: 108.9541, cat: "custom", blurb: "The Western Zhou dynasty (~1046 BCE) institutionalised marriage through the Liuli (Six Rites): a formal proposal, divination of compatibility, exchange of gifts, announcement to ancestors, exchange of betrothal gifts, and the wedding ceremony itself. This framework shaped Chinese marriage custom for three millennia.", src: ["Ebrey, P., The Inner Quarters: Marriage and the Lives of Chinese Women in the Sung Period (1993)","Liji (Book of Rites), Zhou dynasty compilation"] },
  { id: "roman-manus-marriage", year: -500, title: "Roman Manus Marriage Under Paterfamilias", place: "Rome", iso: "IT", lat: 41.8902, lng: 12.4922, cat: "legal", blurb: "Early Roman law (~500 BCE) formalised manus marriage, in which a wife passed entirely from her father's legal authority into her husband's — she held no independent property rights and was juridically a daughter to her husband. This is the earliest well-documented legal framework transferring a woman's personhood through marriage.", src: ["Gardner, J.F., Women in Roman Law and Society (1986)","Treggiari, S., Roman Marriage: Iusti Coniuges (1991)"] },
  { id: "greek-betrothal-engye", year: -500, title: "Athenian Engye: First Formal Betrothal", place: "Athens", iso: "GR", lat: 37.9755, lng: 23.7348, cat: "legal", blurb: "Classical Athenian law formalised the engye (~500 BCE) — a spoken contract between the groom and the bride's kyrios (father or guardian) — as the legal act that created a valid marriage. The bride herself was not a party to the contract, making this the earliest documented legal model of marriage-as-male-property-transfer.", src: ["Harrison, A.R.W., The Law of Athens vol. I: The Family and Property (1968)","Just, R., Women in Athenian Law and Life (1989)"] },
  { id: "twelve-tables-marriage", year: -450, title: "Twelve Tables Define Roman Marriage", place: "Rome", iso: "IT", lat: 41.8902, lng: 12.4922, cat: "legal", blurb: "Rome's Twelve Tables (~450 BCE) — the earliest codified Roman law — specified the usus rule: a woman avoided manus by absenting herself from her husband's home for three consecutive nights annually, establishing the first legal mechanism for a wife to preserve independent property status.", src: ["Crawford, M., Roman Statutes vol. II (1996)","Treggiari, S., Roman Marriage: Iusti Coniuges (1991)"] },
  { id: "roman-free-marriage", year: -450, title: "Roman Law Recognises Consensual Marriage", place: "Rome, Roman Republic", iso: "IT", lat: 41.89, lng: 12.49, cat: "ancient", blurb: "The Twelve Tables codified that marriage required mutual consent of both parties, not merely parental arrangement — one of the earliest legal acknowledgements that the couple's own will mattered. This principle of consensus facit nuptias would anchor Western marriage law for millennia.", src: ["Twelve Tables, Table IV (c. 450 BCE)","Treggiari, S. Roman Marriage (1991)"] },
  { id: "roman-divorce-law", year: -449, title: "Twelve Tables Allow Husband-Initiated Divorce", place: "Rome", iso: "IT", lat: 41.8902, lng: 12.4922, cat: "divorce", blurb: "Rome's Twelve Tables (~449 BCE) gave a husband the right to repudiate his wife by declaring 'Take your things for yourself' (tuas res tibi habeto), codifying the earliest one-sided male-initiated divorce in Western legal tradition. Wives had no equivalent right under early Roman law.", src: ["Watson, A., Rome of the XII Tables (1975)","Treggiari, S., Roman Marriage: Iusti Coniuges (1991)"] },
  { id: "roman-law-repudium", year: -449, title: "Rome's Twelve Tables permit divorce", place: "Rome, Roman Republic", iso: "IT", lat: 41.8929, lng: 12.4823, cat: "divorce", blurb: "The Twelve Tables (c. 449 BCE) formalised the Roman institution of repudium — unilateral dissolution of marriage by either spouse — with the husband simply returning the wife's dowry. By the late Republic, women of means could also initiate divorce, making Rome one of the ancient world's most permissive divorce regimes.", src: ["Twelve Tables, Table IV","Susan Treggiari, Roman Marriage (1991)"] },
  { id: "jewish-ketubah-elephantine", year: -440, title: "Earliest surviving Jewish ketubah", place: "Elephantine, Egypt", iso: "EG", lat: 24.08, lng: 32.9, cat: "religious", blurb: "Aramaic marriage contracts (c. 5th century BCE) from the Jewish military colony at Elephantine are the oldest surviving ketubot, specifying financial obligations to the wife and conditions for divorce. They establish the ketubah as a legally binding religious document protecting women's rights.", src: ["Cowley, A.E., Aramaic Papyri of the Fifth Century BC (1923)","Porten, B., Archives from Elephantine (1968)"] },
  { id: "gandharva-vivaha", year: -300, title: "India Codifies Love-Marriage as Valid", place: "Indian subcontinent", iso: "IN", lat: 20.59, lng: 78.96, cat: "ancient", blurb: "The Manusmriti and earlier Dharmaśāstra texts enumerate eight forms of marriage; Gandharva vivāha — union by mutual love and consent alone, without family ceremony — is listed as one, giving legal standing to love marriage in the Hindu tradition.", src: ["Manusmriti III.27–34 (c. 200 BCE–200 CE)","Kane, P.V. History of Dharmaśāstra Vol. II (1941)"] },
  { id: "roman-marriage", year: -200, title: "Roman marriage & consent", place: "Rome", iso: "IT", lat: 41.9, lng: 12.5, cat: "ancient", blurb: "Rome distinguishes marriage “cum manu” (wife under the husband) from the freer “sine manu”, and makes the consent of both parties central.", src: ["Roman law"] },
  { id: "roman-sine-manu-marriage", year: -200, title: "Sine Manu: Wife Retains Own Property", place: "Rome", iso: "IT", lat: 41.8902, lng: 12.4922, cat: "rights", blurb: "By ~200 BCE sine manu (without hand) marriage had become the dominant Roman form: a wife remained under her father's legal authority, kept her own property separate from her husband's, and could inherit independently. This is the ancient world's clearest legal precursor to married women's separate property rights.", src: ["Gardner, J.F., Women in Roman Law and Society (1986)","Treggiari, S., Roman Marriage: Iusti Coniuges (1991)"] },
  { id: "roman-confarreatio", year: -200, title: "Roman sacred marriage rite formalised", place: "Rome, Italy", iso: "IT", lat: 41.9, lng: 12.5, cat: "religious", blurb: "Confarreatio, the most sacred Roman form of marriage, required a spelt-cake offering to Jupiter Farreus before the Pontifex Maximus and Flamen Dialis; only those born of such a union could hold certain priesthoods. It represents the earliest formalized intersection of state religion and marriage in the Western world.", src: ["Gaius, Institutes I.112","Treggiari, S., Roman Marriage (1991)"] },
  { id: "ketubah", year: -100, title: "The Jewish ketubah", place: "Judea", iso: "IL", lat: 31.78, lng: 35.21, cat: "religious", blurb: "The ketubah — a marriage contract guaranteeing the wife financial protection — becomes standard, an early codified spousal right.", src: ["Mishnah"] },
  { id: "roman-twelve-years", year: -18, title: "Rome codifies 12 as minimum age", place: "Rome, Italy", iso: "IT", lat: 41.9, lng: 12.5, cat: "ancient", blurb: "Roman law under Augustus (Lex Iulia et Papia, 18 BCE onward) crystallised the long-standing custom that girls could not legally marry before age 12 and boys before 14 — ages linked to presumed puberty. This Roman floor became the template for canon law across Europe for nearly two millennia.", src: ["Justinian, Digest 23.2.4","Treggiari, S. (1991). Roman Marriage."] },
  { id: "roman-monogamy-law", year: -18, title: "Rome's Lex Julia bans polygamy", place: "Rome, Italy", iso: "IT", lat: 41.9, lng: 12.5, cat: "legal", blurb: "Augustus's Lex Julia de maritandis ordinibus restricted citizens to one legal spouse at a time, embedding monogamy in Roman civil law. This legislation became the legal ancestor of Western European marriage norms.", src: ["Lex Julia de maritandis ordinibus, 18 BCE","Treggiari, S. — Roman Marriage (1991)"] },
  { id: "mishnah-kiddushin-codified", year: 200, title: "Mishnah codifies Jewish betrothal law", place: "Galilee, Roman Palestine", iso: "IL", lat: 32.8, lng: 35.5, cat: "religious", blurb: "Tractate Kiddushin of the Mishnah (c. 200 CE) formally codified the three modes of betrothal — money, document, and intercourse — and established the rabbinic framework for Jewish marriage that persists in Orthodox communities today. It transformed biblical custom into systematic religious law.", src: ["Mishnah Kiddushin 1:1","Epstein, L.M., The Jewish Marriage Contract (1927)"] },
  { id: "rome-conubium-elagabalus", year: 221, title: "Roman Emperor Marries a Man", place: "Rome, Roman Empire", iso: "IT", lat: 41.9, lng: 12.5, cat: "ancient", blurb: "Emperor Elagabalus (reigned 218–222 CE) publicly married the slave Hierocles and later the charioteer Zoticus in ceremonies that Roman sources describe with wedding rites. These are among the earliest recorded same-sex marriages involving a head of state.", src: ["Historia Augusta, Life of Elagabalus","Cassius Dio, Roman History 80.13–16"] },
  { id: "christian-monogamy-doctrine", year: 350, title: "Church fathers declare monogamy divine", place: "Carthage (Tunis), Tunisia", iso: "TN", lat: 36.85, lng: 10.32, cat: "religious", blurb: "Synods in North Africa, building on Augustine of Hippo's theology, firmly condemned plural marriage as contrary to Christian teaching, making monogamy a doctrinal requirement across the Latin Church.", src: ["Augustine, De bono coniugali (c. 401)","Clark, G. — Women in Late Antiquity (1993)"] },
  { id: "christian-sacrament-augustine", year: 401, title: "Augustine defines marriage as sacrament", place: "Hippo Regius (Annaba), Algeria", iso: "DZ", lat: 36.9, lng: 7.77, cat: "religious", blurb: "Augustine's De bono coniugali (401 CE) articulated the three goods of marriage — offspring, fidelity, and sacrament (proles, fides, sacramentum) — laying the theological foundation for Christian marriage as an indissoluble sacred bond. This framework dominated Western ecclesiastical law for over a millennium.", src: ["Augustine, De bono coniugali (401 CE)","Reynolds, P.L., Marriage in the Western Church (1994)"] },
  { id: "nikah-mahr", year: 620, title: "Islamic nikah & mahr", place: "Medina, Arabia", iso: "SA", lat: 24.47, lng: 39.61, cat: "religious", blurb: "Islamic law makes marriage a contract requiring the bride’s consent and a mahr (dower) paid to her, and limits polygamy to four wives.", src: ["Qur’an"] },
  { id: "islamic-nikah-quran", year: 622, title: "Quranic nikah and mahr established", place: "Medina, Arabia", iso: "SA", lat: 24.47, lng: 39.61, cat: "religious", blurb: "The Quran (Surah 4: An-Nisa) and the early Medinan community formalised the nikah contract and the mandatory mahr (dower paid by the groom to the bride), giving women enforceable property rights within marriage. The Prophet's own marriage practices and hadith became the template for Islamic marriage law across all schools.", src: ["Quran 4:4, 4:24–25","Esposito, J.L., Women in Muslim Family Law (1982)"] },
  { id: "charlemagne-polygamy-ban", year: 789, title: "Charlemagne outlaws polygamy in Frankia", place: "Aachen, Frankia (Germany)", iso: "DE", lat: 50.78, lng: 6.08, cat: "legal", blurb: "Charlemagne's Admonitio Generalis (789) imposed strict ecclesiastical monogamy across the Frankish Empire, the first major secular ruler to legislate Christian marriage norms over a wide European territory.", src: ["Admonitio Generalis (789 CE)","McKitterick, R. — The Frankish Church and the Carolingian Reforms (1977)"] },
  { id: "charlemagne-church-marriage-decree", year: 802, title: "Charlemagne mandates church blessing", place: "Aachen, Frankish Empire", iso: "DE", lat: 50.77, lng: 6.08, cat: "religious", blurb: "Charlemagne's 802 capitularies required that all marriages receive a priestly blessing, marking the first major secular legislation compelling Christian ecclesiastical involvement in marriage across a large polity. This was a decisive step toward the Church's monopoly over marriage in medieval Europe.", src: ["MGH Capitularia Regum Francorum I, no. 33 (802)","Brooke, C.N.L., The Medieval Idea of Marriage (1989)"] },
  { id: "rabbeinu-gershom-ban", year: 1000, title: "Rabbi Gershom bans Jewish polygyny", place: "Mainz, Holy Roman Empire (Germany)", iso: "DE", lat: 49.99, lng: 8.27, cat: "religious", blurb: "Rabbeinu Gershom Me'or HaGolah issued a taqqanah (rabbinic ordinance) around 1000 CE prohibiting Ashkenazi Jewish men from taking multiple wives, a ban that spread across European Jewish communities and effectively ended polygyny in the diaspora.", src: ["Taqqanot Rabbenu Gershom (c. 1000)","Epstein, L.M. — Marriage Laws in the Bible and Talmud (1942)"] },
  { id: "gratian-decretum-marriage-canon", year: 1140, title: "Gratian's Decretum: canon marriage law", place: "Bologna, Italy", iso: "IT", lat: 44.49, lng: 11.34, cat: "religious", blurb: "Gratian's Concordia Discordantium Canonum (c. 1140) synthesised centuries of Church rulings into the first systematic canon law of marriage, establishing consent as the constitutive element and indissolubility as the norm. Bologna became the birthplace of Western marriage jurisprudence that shaped European law for centuries.", src: ["Gratian, Decretum C.27–C.36 (c. 1140)","Noonan, J.T., 'Power to Choose', Viator 4 (1973)"] },
  { id: "church-sacrament", year: 1184, title: "Marriage becomes a sacrament", place: "Verona, Europe", iso: "IT", lat: 45.44, lng: 10.99, cat: "religious", blurb: "The medieval Church lists marriage among the sacraments, bringing it firmly under religious law across Christian Europe.", src: ["Council of Verona"] },
  { id: "fourth-lateran-council-banns", year: 1215, title: "Lateran IV requires public banns", place: "Rome, Italy", iso: "IT", lat: 41.89, lng: 12.5, cat: "religious", blurb: "The Fourth Lateran Council (1215) mandated that intended marriages be publicly announced in church on three successive Sundays — the banns — to allow the community to raise objections such as bigamy or consanguinity. This was the first Church-wide procedural safeguard against clandestine and irregular marriages.", src: ["Fourth Lateran Council, Canon 51 (1215)","Brundage, J.A., Law, Sex, and Christian Society in Medieval Europe (1987)"] },
  { id: "lateran-iv-banns", year: 1215, title: "Banns of marriage required by Church", place: "Rome (Lateran Palace), Papal States", iso: "IT", lat: 41.88, lng: 12.5, cat: "religious", blurb: "Canon 51 of the Fourth Lateran Council (1215) mandated that intended marriages be publicly announced on three successive Sundays so that anyone knowing of an impediment could object — the origin of the banns of marriage still used today. The Council also forbade clandestine marriages.", src: ["https://en.wikipedia.org/wiki/Banns_of_marriage","https://www.newadvent.org/cathen/02255a.htm"] },
  { id: "christian-church-marriage", year: 1215, title: "Church Declares Marriage a Sacrament", place: "Rome (Fourth Lateran Council)", iso: "IT", lat: 41.9, lng: 12.5, cat: "religious", blurb: "The Fourth Lateran Council formally defined marriage as one of the seven sacraments and required banns to be read in church before any wedding, wresting control of marriage from families and local custom and placing it firmly under ecclesiastical authority across Catholic Europe.", src: ["Fourth Lateran Council, Canon 51 (1215)","Brundage, J.A. Law, Sex and Christian Society in Medieval Europe (1987)"] },
  { id: "canon-law-twelve-fourteen", year: 1234, title: "Church sets 12/14 rule in canon law", place: "Rome (Papal States)", iso: "VA", lat: 41.9, lng: 12.45, cat: "religious", blurb: "Pope Gregory IX's Decretales (1234) enshrined 12 for girls and 14 for boys as the universal minimum marriage ages throughout Catholic Christendom, inheriting the Roman standard. This canon law norm governed marriage across Western Europe for centuries and influenced secular codes worldwide.", src: ["Decretales Gregorii IX, X.4.2.3","Brundage, J.A. (1987). Law, Sex, and Christian Society in Medieval Europe."] },
  { id: "ottoman-polygamy-legal", year: 1453, title: "Ottoman Empire formalises Islamic polygyny", place: "Constantinople (Istanbul), Turkey", iso: "TR", lat: 41.01, lng: 28.98, cat: "polygamy", blurb: "The Ottoman Kanunname codified Islamic law permitting up to four wives under the condition of equal treatment, making the empire one of the most influential states to institutionalise plural marriage across three continents.", src: ["Ottoman Kanunname-i Al-i Osman","Imber, C. — The Ottoman Empire 1300–1650 (2002)"] },
  { id: "sikh-anand-karaj", year: 1506, title: "Guru Nanak composes Anand Karaj hymn", place: "Punjab region", iso: "IN", lat: 31.15, lng: 75.34, cat: "religious", blurb: "Guru Nanak composed the Laavan (four stanzas of Anand Karaj) in the early 16th century, establishing the Sikh marriage ceremony as a spiritual journey around the Guru Granth Sahib rather than a legal contract. The Anand Marriage Act (1909) later gave Anand Karaj formal legal recognition in British India.", src: ["Guru Granth Sahib, Laavan (Suri 773–774)","McLeod, W.H., Sikhism (1997)"] },
  { id: "protestant-marriage-civil-reform", year: 1520, title: "Luther rejects marriage as sacrament", place: "Wittenberg, Saxony", iso: "DE", lat: 51.87, lng: 12.64, cat: "religious", blurb: "Martin Luther's Babylonian Captivity of the Church (1520) denied that marriage was a sacrament instituted by Christ, re-framing it as a civil and social institution blessed by God — directly spurring Protestant states to transfer marriage jurisdiction from Church courts to civil authorities. This theological break created the template for secular marriage in the modern West.", src: ["Luther, De captivitate Babylonica ecclesiae (1520)","Ozment, S., When Fathers Ruled (1983)"] },
  { id: "trent", year: 1563, title: "Council of Trent formalises weddings", place: "Trent, Italy", iso: "IT", lat: 46.07, lng: 11.12, cat: "religious", blurb: "Trent’s “Tametsi” decree requires a priest and witnesses, ending clandestine marriage in the Catholic world.", src: ["Council of Trent"] },
  { id: "council-of-trent-matrimony", year: 1563, title: "Trent mandates priest and witnesses", place: "Trent, Prince-Bishopric of Trent (Italy)", iso: "IT", lat: 46.07, lng: 11.12, cat: "religious", blurb: "Session XXIV of the Council of Trent (1563), the Tametsi decree, declared that a valid Catholic marriage required the presence of a parish priest and two witnesses, abolishing clandestine marriages and creating a register system. This was the most consequential reform of Christian marriage law before the modern era.", src: ["Council of Trent, Session XXIV, Tametsi decree (1563)","Gaudemet, J., Le mariage en Occident (1987)"] },
  { id: "tametsi-parish-register", year: 1563, title: "Parish registers mandated by Trent", place: "Trent, Holy Roman Empire", iso: "IT", lat: 46.07, lng: 11.12, cat: "religious", blurb: "Session XXIV of the Council of Trent (1563) issued the Tametsi decree, requiring every Catholic parish to keep a formal written register of marriages and to publish banns on three feast days before the ceremony. This was the first systematic, universally-mandated written record of marriages in the Western world.", src: ["https://en.wikipedia.org/wiki/Tametsi","https://www.catholicculture.org/culture/library/dictionary/index.cfm?id=36775"] },
  { id: "council-of-trent-indissoluble", year: 1563, title: "Council of Trent bans Catholic divorce", place: "Trent, Holy Roman Empire", iso: "IT", lat: 46.0748, lng: 11.1217, cat: "religious", blurb: "The Council of Trent (1545–1563) dogmatically defined Catholic marriage as an indissoluble sacrament and condemned Protestantism's allowance of divorce for adultery or desertion. This decree locked divorce out of canon law for centuries and shaped the legal systems of every predominantly Catholic country.", src: ["Council of Trent, Session XXIV, Canones de Matrimonio (1563)","John Noonan, Power to Dissolve (1972)"] },
  { id: "council-of-trent-consent", year: 1563, title: "Trent Makes Couple's Consent Mandatory", place: "Trento, Italy", iso: "IT", lat: 46.07, lng: 11.12, cat: "religious", blurb: "The Council of Trent's decree Tametsi declared clandestine marriages invalid and required a priest and two witnesses — but crucially reaffirmed that free consent of bride and groom, not parental approval, was the essential element, outlawing forced marriage across Catholic Europe.", src: ["Council of Trent, Session XXIV, Decree Tametsi (1563)","Gaudemet, J. Le Mariage en Occident (1987)"] },
  { id: "shulchan-aruch-jewish-marriage", year: 1565, title: "Shulchan Aruch codifies Jewish marriage", place: "Safed, Ottoman Palestine", iso: "IL", lat: 32.96, lng: 35.49, cat: "religious", blurb: "Joseph Karo's Shulchan Aruch (1565), Even HaEzer section, standardised the rules of kiddushin (betrothal), the ketubah, chuppah, and seven blessings across the Jewish diaspora for the first time. It remains the authoritative code for Orthodox Jewish marriage practice worldwide.", src: ["Karo, J., Shulchan Aruch, Even HaEzer (1565)","Lamm, M., The Jewish Way in Love and Marriage (1980)"] },
  { id: "dutch-civil", year: 1580, title: "First civil marriage", place: "Dutch Republic", iso: "NL", lat: 52.37, lng: 4.9, cat: "legal", blurb: "The Netherlands lets couples marry before a magistrate instead of the church — a pioneering separation of marriage from religion.", src: ["Dutch Republic statutes"] },
  { id: "dutch-politieke-ordonnantie", year: 1580, title: "Civil authority takes over marriage law", place: "Province of Holland, Dutch Republic", iso: "NL", lat: 52.37, lng: 4.9, cat: "legal", blurb: "The Politieke Ordonnantie of 1580 transferred jurisdiction over marriage from the Catholic Church to secular (civil) courts in the newly Protestant Dutch provinces, making it one of the earliest instances of civil marriage law in the world. Amsterdam introduced separate civil marriage banns registers from 1578, predating the ordinance.", src: ["https://www.academia.edu/72181495/Counting_Couples_The_Marriage_Banns_Registers_of_the_City_of_Amsterdam_1580_1810","https://brill.com/view/journals/rdj/6/1/article-p1_2.xml"] },
  { id: "massachusetts-bay-license", year: 1639, title: "First marriage licenses in the Americas", place: "Massachusetts Bay Colony", iso: "US", lat: 42.36, lng: -71.06, cat: "legal", blurb: "Puritan leaders of Massachusetts Bay Colony declared marriage a civil — not religious — matter and required magistrate-issued licenses from around 1639, the first formal marriage-licensing system in the Americas. Governor William Bradford had declared as early as 1620 that marriage 'should be performed by the magistrate, as being a civil thing.'", src: ["https://theamm.org/articles/1530-a-short-history-of-the-marriage-license-common-law-marriages","https://en.wikipedia.org/wiki/Marriage_license"] },
  { id: "massachusetts-bay-first-divorce", year: 1643, title: "First Legal Divorce in America Granted", place: "Boston, Massachusetts", iso: "US", lat: 42.3601, lng: -71.0589, cat: "divorce", blurb: "On 5 January 1643, the Quarter Court of Boston granted Anne Clarke the first legally recorded divorce in the American colonies, on grounds of adultery by her husband Dennis Clarke. It established the colonial precedent that civil courts — not ecclesiastical ones — could dissolve marriages, a foundation for later women's divorce rights in the United States.", src: ["https://prologue.blogs.archives.gov/2023/07/17/not-just-suffrage-divorce-and-the-seneca-falls-convention/","https://www.jlmfamilylaw.com/post/divorce-history-women-s-rights-international-women-s-day"] },
  { id: "virginia-anti-miscegenation", year: 1691, title: "Virginia Bans Interracial Marriage", place: "Jamestown, Virginia, USA", iso: "US", lat: 37.21, lng: -76.78, cat: "legal", blurb: "Virginia's Act for Suppression of Outlying Slaves was the first colonial law explicitly banning marriage between white colonists and 'Negroes, mulattoes, or Indians,' establishing the template for anti-miscegenation statutes that would spread across North America and persist for nearly three centuries.", src: ["Virginia Acts of Assembly, Act XVI (1691)","Pascoe, P. What Comes Naturally (2009)"] },
  { id: "hardwicke", year: 1753, title: "Marriage Act formalises weddings", place: "England", iso: "GB", lat: 51.5, lng: -0.12, cat: "legal", blurb: "Lord Hardwicke’s Act requires formal ceremonies, banns and registers in England, ending secret “Fleet” marriages.", src: ["Marriage Act 1753"] },
  { id: "england-hardwicke-act", year: 1753, title: "Hardwicke Act: first English marriage statute", place: "Westminster, England", iso: "GB", lat: 51.5, lng: -0.12, cat: "legal", blurb: "Lord Hardwicke's Clandestine Marriages Act 1753 was the first statutory law in England requiring a formal ceremony, published banns or a licence, and a printed register on durable paper — ending informal Fleet prison marriages. It came into force on 25 March 1754.", src: ["https://en.wikipedia.org/wiki/Clandestine_Marriages_Act_1753","https://historycooperative.org/the-history-of-hardwickes-marriage-act/"] },
  { id: "marriage-act-1753", year: 1753, title: "England Outlaws Clandestine Love Marriages", place: "London, England", iso: "GB", lat: 51.5, lng: -0.13, cat: "legal", blurb: "Lord Hardwicke's Marriage Act 1753 — the first statute to regulate marriage in England — banned the Fleet Street clandestine marriages popular with eloping couples, requiring banns or a licence, a church ceremony, and parental consent for those under 21, pushing elopements across the border to Gretna Green in Scotland.", src: ["Marriage Act 1753, 26 Geo. II c. 33","Stone, L. Road to Divorce (1990)"] },
  { id: "france-civil-marriage-1791", year: 1791, title: "French Revolution makes marriage a civil contract", place: "Paris, France", iso: "FR", lat: 48.85, lng: 2.35, cat: "legal", blurb: "The French National Assembly's Constitution of 1791 declared that 'the law considers marriage only as a civil contract,' stripping the Church of legal authority over matrimony — the first nation-state to mandate a purely secular civil marriage ceremony before any religious rite. Municipal registries replaced church registers.", src: ["https://grokipedia.com/page/Civil_marriage","https://blogs.loc.gov/law/2017/09/matrimonial-relations-european-law-and-religious-communities/"] },
  { id: "french-civil-marriage", year: 1792, title: "France Creates Secular Civil Marriage", place: "Paris, France", iso: "FR", lat: 48.85, lng: 2.35, cat: "legal", blurb: "Revolutionary France's September 1792 law made civil marriage before a municipal officer the only legally binding form, stripping the Church of its monopoly on marriage registration and establishing the secular state-registered marriage model that would spread across the world.", src: ["French Law of 20 September 1792","Phillips, R. Putting Asunder (1988)"] },
  { id: "netherlands-civil-marriage-mandatory", year: 1795, title: "Netherlands mandates civil ceremony for all", place: "The Hague, Batavian Republic", iso: "NL", lat: 52.08, lng: 4.31, cat: "legal", blurb: "Following the French Revolutionary-inspired Batavian Republic, the Netherlands from 1795 required that ALL marriages — regardless of religion — be performed as a civil ceremony before a municipal registrar, one of the earliest full secular mandates in the world; religious ceremonies became legally optional and subordinate.", src: ["https://www.familysearch.org/en/wiki/Netherlands_Civil_Registration","https://www.familysearch.org/en/wiki/Netherlands_-_Dutch_Civil_Registration_-_Marriage_Related_Records_(National_Institute)"] },
  { id: "england-register-office-1836", year: 1836, title: "England's General Register Office established", place: "London, England", iso: "GB", lat: 51.5, lng: -0.12, cat: "legal", blurb: "The Marriage Act 1836 created the General Register Office and 619 local registration districts in England and Wales, enabling legal civil marriage in a register office for the first time from 30 June 1837. Non-Anglicans — Catholics, Dissenters, atheists — could at last marry without submitting to Church of England rites.", src: ["https://en.wikipedia.org/wiki/Marriage_Act_1836","https://www.qualifiedgenealogists.org/RQGNews/blog/civil-marriage"] },
  { id: "england-civil", year: 1837, title: "Civil registration of marriage", place: "England", iso: "GB", lat: 51.5, lng: -0.12, cat: "legal", blurb: "England introduces civil marriage and central registration, allowing secular and non-Anglican weddings.", src: ["Marriage Act 1836"] },
  { id: "england-custody-of-infants-act", year: 1839, title: "Mothers Win First Custody Rights", place: "London, England", iso: "GB", lat: 51.5074, lng: -0.1278, cat: "rights", blurb: "England's Custody of Infants Act 1839 — championed by Caroline Norton — was the first legislation to break the common-law rule that children belonged entirely to the father. It allowed non-adulterous mothers to petition for custody of children under seven, a watershed legal recognition that mothers held independent rights over their offspring.", src: ["https://en.wikipedia.org/wiki/Custody_of_Infants_Act_1839","https://womenslegallandmarks.com/2017/08/08/matrimonial-causes-act-1857/"] },
  { id: "mississippi-married-women-property", year: 1839, title: "First Law Letting Wives Own Property", place: "Mississippi, USA", iso: "US", lat: 32.3547, lng: -89.3985, cat: "legal", blurb: "Mississippi's Married Women's Property Act of 1839 was the first law in the United States — and among the first in the world — to allow a married woman to own property in her own name, shielding it from her husband's creditors. Rooted in the Fisher v. Allen case brought by Betsy Love, it cracked open coverture and sparked similar legislation across other states.", src: ["https://www.britannica.com/event/Married-Womens-Property-Acts-United-States-1839","https://www.mshistorynow.mdah.ms.gov/issue/betsy-love-and-the-mississippi-married-womens-property-act-of-1839"] },
  { id: "white-wedding", year: 1840, title: "The white wedding dress", place: "England", iso: "GB", lat: 51.5, lng: -0.12, cat: "custom", blurb: "Queen Victoria’s white gown popularises the white wedding dress, reshaping wedding fashion around the world.", src: ["historical record"] },
  { id: "white-wedding-dress", year: 1840, title: "Victoria's White Dress Sets Global Custom", place: "Chapel Royal, St. James's Palace, London", iso: "GB", lat: 51.5, lng: -0.14, cat: "custom", blurb: "Queen Victoria wore white satin at her wedding to Prince Albert on 10 February 1840, departing from the colourful or silver gowns favoured by royalty; the widely published images sparked an enduring global custom that equated the white wedding dress with bridal purity and romance.", src: ["Illustrated London News, 15 Feb 1840","Friese, K. Victorian Wedding Dress (2004)"] },
  { id: "lds-polygamy-revelation", year: 1843, title: "Joseph Smith reveals plural marriage doctrine", place: "Nauvoo, Illinois, USA", iso: "US", lat: 40.55, lng: -91.39, cat: "religious", blurb: "Joseph Smith dictated Section 132 of the Doctrine and Covenants, presenting 'celestial plural marriage' as divine commandment, launching the most prominent modern polygamy movement in a Western democracy.", src: ["Doctrine & Covenants §132 (1843)","Compton, T. — In Sacred Loneliness (1997)"] },
  { id: "new-york-married-women-property-1848", year: 1848, title: "New York's Property Act Sets US Template", place: "Albany, New York, USA", iso: "US", lat: 42.6526, lng: -73.7562, cat: "legal", blurb: "New York's Married Women's Property Act of 1848 went further than Mississippi's 1839 law by granting wives full control — not just nominal ownership — of pre-marital and inherited property. Passed the same year as the Seneca Falls Convention, it became the legislative template that other U.S. states and eventually Britain modelled their own acts upon.", src: ["https://wams.nyhistory.org/expansions-and-inequalities/politics-and-society/married-womens-property-act/","https://wisc.pb.unizin.org/ls261/chapter/ch-5-1-married-womens-property-acts/"] },
  { id: "ottoman-millet-marriage-law", year: 1856, title: "Ottoman Tanzimat reforms millet marriage", place: "Constantinople (Istanbul), Ottoman Empire", iso: "TR", lat: 41.01, lng: 28.97, cat: "religious", blurb: "The 1856 Hatt-ı Hümayun confirmed that each recognised religious community (millet) — Muslim, Jewish, Greek Orthodox, Armenian — retained sole jurisdiction over the marriages of its members under its own religious law. This was the most explicit pre-modern legal pluralism enshrining religious marriage autonomy across a multi-faith empire.", src: ["Hatt-ı Hümayun (1856)","Ginio, E., 'Living on the Margins of Charity', in Poverty and Charity in Middle Eastern Contexts (2003)"] },
  { id: "england-matrimonial-causes-act", year: 1857, title: "England Opens Civil Divorce Courts", place: "London, England", iso: "GB", lat: 51.5074, lng: -0.1278, cat: "divorce", blurb: "The Matrimonial Causes Act 1857 transferred divorce from expensive ecclesiastical courts to accessible civil courts, giving English women for the first time a statutory right to petition for divorce (though on narrower grounds than men). It also allowed divorced women to own property and enter contracts — a first fracture in the doctrine of coverture under English law.", src: ["https://en.wikipedia.org/wiki/Matrimonial_Causes_Act_1857","https://womenslegallandmarks.com/2017/08/08/matrimonial-causes-act-1857/"] },
  { id: "england-divorce-act-1857", year: 1857, title: "England creates secular divorce court", place: "London, England", iso: "GB", lat: 51.4994, lng: -0.1248, cat: "legal", blurb: "The Matrimonial Causes Act 1857 transferred divorce jurisdiction from Parliament (where a private Act costing thousands was required) to a new civil court, making divorce accessible to the middle class for the first time in England. Crucially it retained a double standard: a husband could divorce a wife for adultery alone, but a wife needed to prove aggravated adultery, cruelty, or desertion.", src: ["Matrimonial Causes Act 1857, 20 & 21 Vict. c.85","Lawrence Stone, Road to Divorce (1990)"] },
  { id: "us-morrill-anti-bigamy-act", year: 1862, title: "USA criminalises polygamy federally", place: "Washington D.C., USA", iso: "US", lat: 38.9, lng: -77.04, cat: "legal", blurb: "The Morrill Anti-Bigamy Act made polygamy a federal crime specifically targeting LDS practice in US territories, beginning three decades of legal conflict that culminated in the Church officially abandoning plural marriage in 1890.", src: ["Morrill Anti-Bigamy Act, 37th U.S. Congress (1862)","Gordon, S.B. — The Mormon Question (2002)"] },
  { id: "prussia-civil-marriage-kulturkampf", year: 1874, title: "Prussia strips Church of marriage authority", place: "Berlin, German Empire", iso: "DE", lat: 52.52, lng: 13.4, cat: "legal", blurb: "Bismarck's Kulturkampf culminated in a March 1874 Prussian law requiring mandatory civil ceremonies before a civil registrar, extended empire-wide in 1875. This broke the Catholic Church's centuries-long monopoly on marriage registration in German territories and established the modern German Standesamt (civil registry) system.", src: ["https://en.wikipedia.org/wiki/Kulturkampf","https://www.britannica.com/event/Kulturkampf"] },
  { id: "mwpa", year: 1882, title: "Married Women’s Property Act", place: "United Kingdom", iso: "GB", lat: 51.5, lng: -0.12, cat: "rights", blurb: "Wives win the right to own and control their own property, dismantling “coverture”, which had merged a wife’s legal identity into her husband’s.", src: ["Married Women's Property Act 1882"] },
  { id: "uk-married-women-property-act-1882", year: 1882, title: "England Ends Coverture Over Property", place: "London, England", iso: "GB", lat: 51.5074, lng: -0.1278, cat: "legal", blurb: "The Married Women's Property Act 1882 granted every married woman in England, Wales, and Ireland full ownership and control of all property she held before or acquired during marriage, effectively dismantling coverture. For the first time, a wife could sue, be sued, enter contracts, and support herself independently of her husband — a legal transformation historians rank alongside suffrage itself.", src: ["https://en.wikipedia.org/wiki/Married_Women's_Property_Act_1882","https://wslaw.co.uk/blog/empowering-women-and-engaged-couples-reflecting-on-the-legacy-of-the-married-womens-property-act-1882/"] },
  { id: "lds-manifesto-1890", year: 1890, title: "LDS Church officially ends plural marriage", place: "Salt Lake City, Utah, USA", iso: "US", lat: 40.76, lng: -111.89, cat: "religious", blurb: "LDS President Wilford Woodruff issued the Official Declaration (Manifesto) ending the sanction of new plural marriages, after sustained federal pressure and property confiscation, marking the largest voluntary abandonment of institutionalised polygamy in American history.", src: ["Official Declaration 1 (Manifesto), LDS Church (1890)","Hardy, B.C. — Solemn Covenant (1992)"] },
  { id: "sweden-mutual-divorce-1915", year: 1915, title: "Sweden allows mutual-consent divorce", place: "Stockholm, Sweden", iso: "SE", lat: 59.3293, lng: 18.0686, cat: "legal", blurb: "Sweden's 1915 Marriage Code (implemented 1920) permitted divorce by mutual consent after a one-year separation — one of the earliest Western nations to move decisively away from fault-only grounds. It foreshadowed the Nordic model of divorce as an administrative rather than punitive process.", src: ["Swedish Marriage Code 1915 (Giftermålsbalken)","Eva Österberg & Sølvi Sogner, People and Space (2000)"] },
  { id: "ussr-nofault", year: 1917, title: "First no-fault divorce", place: "Russia", iso: "RU", lat: 55.75, lng: 37.62, cat: "divorce", blurb: "Revolutionary Russia introduces easy civil divorce and civil marriage and equalises spouses’ rights — radical for its time.", src: ["1918 Family Code"] },
  { id: "canon-law-1917-codex", year: 1917, title: "Catholic Code of Canon Law on marriage", place: "Vatican City", iso: "VA", lat: 41.9, lng: 12.45, cat: "religious", blurb: "The 1917 Codex Iuris Canonici (canons 1012–1143) consolidated all Catholic marriage law into one binding code for the universal Church for the first time, affirming the sacramental character, the impediments, and the annulment process. It replaced a thousand years of accumulated conciliar and papal decrees with a single authoritative text.", src: ["Codex Iuris Canonici (1917), cc. 1012–1143","Coriden, J.A., An Introduction to Canon Law (2004)"] },
  { id: "soviet-decree-divorce-1917", year: 1917, title: "USSR: world's first no-fault divorce", place: "Petrograd (St Petersburg), Russia", iso: "RU", lat: 59.9343, lng: 30.3351, cat: "divorce", blurb: "The Bolshevik Decree on Divorce (December 1917) was the world's first no-fault divorce law: either spouse could dissolve a marriage by simple declaration, with no grounds required and no judicial hearing needed. This revolutionary measure — mirrored in the 1918 Family Code — preceded Western no-fault reform by over half a century.", src: ["Decree on Divorce, 18 Dec 1917, Sovnarkom","Wendy Goldman, Women, the State and Revolution (1993)"] },
  { id: "soviet-union-marriage-code-1918", year: 1918, title: "Soviet Code Declares Spouses Equal", place: "Moscow, Russia", iso: "RU", lat: 55.7558, lng: 37.6173, cat: "legal", blurb: "The Soviet Code on Marriage, Family, and Guardianship (October 1918) was the world's first national law to declare husband and wife fully equal under matrimonial law. It allowed either party to initiate divorce without grounds, abolished illegitimacy, let couples take either surname, and criminalised marital rape — comparable legislation would not appear in Western Europe for decades.", src: ["https://www.encyclopedia.com/history/encyclopedias-almanacs-transcripts-and-maps/family-code-marriage-family-and-guardianship","https://www.revolutionarydemocracy.org/archive/marriage.htm"] },
  { id: "soviet-union-marital-rape-crime", year: 1922, title: "First Nation Criminalises Marital Rape", place: "Moscow, Russia", iso: "RU", lat: 55.7558, lng: 37.6173, cat: "rights", blurb: "The Soviet Union became the first nation in the world to explicitly criminalise marital rape in 1922, rejecting the centuries-old common-law fiction that marriage constituted irrevocable consent. Poland followed in 1932 and Sweden in 1965; most Western nations did not act until the 1980s–1990s.", src: ["https://en.wikipedia.org/wiki/Marital_rape","https://en.wikipedia.org/wiki/Marital_rape_laws_by_country"] },
  { id: "uk-equal-divorce-grounds-1923", year: 1923, title: "Wives Get Equal Divorce Grounds in UK", place: "London, England", iso: "GB", lat: 51.5074, lng: -0.1278, cat: "divorce", blurb: "The Matrimonial Causes Act 1923 equalised divorce law in England and Wales, allowing a wife to petition for divorce on the sole ground of adultery — the same right her husband had held since 1857. It was the first time English law treated men and women identically in the grounds for ending a marriage.", src: ["https://britishonlinearchives.com/posts/category/notable-days/642/100-years-matrimonial-causes-act-of-1923","https://en.wikipedia.org/wiki/Matrimonial_Causes_Act_1857"] },
  { id: "uk-equal-grounds-1923", year: 1923, title: "UK equalises divorce grounds by sex", place: "London, England", iso: "GB", lat: 51.4994, lng: -0.1248, cat: "rights", blurb: "The Matrimonial Causes Act 1923 abolished the 1857 double standard, allowing wives to petition for divorce on adultery alone — the same single ground available to husbands. It was the first law in England to put men and women on equal legal footing in divorce.", src: ["Matrimonial Causes Act 1923, 13 & 14 Geo. 5, c.19","Gail Savage, 'The Operation of the 1857 Divorce Act', J. Soc. Hist. (1983)"] },
  { id: "turkey-civil", year: 1926, title: "Turkey bans polygamy", place: "Turkey", iso: "TR", lat: 39.93, lng: 32.86, cat: "polygamy", blurb: "Atatürk’s Civil Code abolishes polygamy and religious marriage law, mandating civil, monogamous marriage with equal divorce rights.", src: ["Turkish Civil Code 1926"] },
  { id: "turkey-civil-code-1926", year: 1926, title: "Turkey abolishes polygamy by civil code", place: "Ankara, Turkey", iso: "TR", lat: 39.93, lng: 32.86, cat: "legal", blurb: "Atatürk's Turkish Civil Code of 1926, modelled on the Swiss Civil Code, abolished polygamy and gave women equal divorce rights — the first majority-Muslim nation-state to ban plural marriage by secular legislation.", src: ["Turkish Civil Code No. 743 (1926)","Kandiyoti, D. — Women, Islam and the State (1991)"] },
  { id: "india-child", year: 1929, title: "Child Marriage Restraint Act", place: "India", iso: "IN", lat: 28.61, lng: 77.21, cat: "age", blurb: "British India’s “Sarda Act” sets minimum marriage ages — an early legal push against child marriage.", src: ["Child Marriage Restraint Act 1929"] },
  { id: "england-age-of-marriage-act-1929", year: 1929, title: "England raises minimum age to 16", place: "London, United Kingdom", iso: "GB", lat: 51.5, lng: -0.13, cat: "age", blurb: "The Age of Marriage Act 1929 abolished the ancient 12/14 Roman-canon floor and set 16 as the minimum age for marriage in England and Wales, one of the earliest such statutory rises in a major common-law country. It made marriages below that age void rather than merely voidable.", src: ["Age of Marriage Act 1929 (19 & 20 Geo 5 c.36)","Gillis, J.R. (1985). For Better, For Worse: British Marriages 1600 to the Present."] },
  { id: "india-child-marriage-restraint-1929", year: 1929, title: "India's Sarda Act first bans child marriage", place: "New Delhi, India", iso: "IN", lat: 28.6, lng: 77.2, cat: "legal", blurb: "The Child Marriage Restraint Act 1929 (the 'Sarda Act'), passed by British India's legislature, was the first national law in South Asia to set statutory minimums — 14 for girls and 18 for boys — and criminally penalise those who arranged underage unions. It was landmark legislation driven by Indian reformers, though enforcement remained weak for decades.", src: ["Child Marriage Restraint Act, 1929 (Act XIX of 1929)","Nair, J. (1996). Women and Law in Colonial India."] },
  { id: "un-declaration-consent-1948", year: 1948, title: "UN declares free consent essential", place: "Paris, France", iso: "FR", lat: 48.85, lng: 2.35, cat: "rights", blurb: "Article 16 of the Universal Declaration of Human Rights (1948) proclaimed that marriage shall be entered into only with the 'free and full consent' of intending spouses, implicitly condemning forced and child marriages at an international level for the first time. This laid the human-rights foundation for all subsequent treaty law on minimum marriage age.", src: ["Universal Declaration of Human Rights, Art. 16 (UN, 1948)","Rehman, J. (2010). International Human Rights Law."] },
  { id: "perez-v-sharp", year: 1948, title: "California Strikes Down Interracial Marriage Ban", place: "Sacramento, California, USA", iso: "US", lat: 38.58, lng: -121.49, cat: "rights", blurb: "In Perez v. Sharp, the California Supreme Court became the first US court to invalidate an anti-miscegenation statute, ruling 4–3 that the state ban on marriage between white and non-white persons violated the Fourteenth Amendment's equal protection guarantee — nineteen years before the US Supreme Court reached the same conclusion nationally.", src: ["Perez v. Sharp, 32 Cal.2d 711 (1948)","Pascoe, P. What Comes Naturally (2009)"] },
  { id: "china-1950", year: 1950, title: "China’s Marriage Law", place: "China", iso: "CN", lat: 39.9, lng: 116.4, cat: "rights", blurb: "The new PRC bans arranged and child marriage, concubinage and polygamy, and grants women equal rights to divorce.", src: ["PRC Marriage Law 1950"] },
  { id: "india-special-marriage-act", year: 1954, title: "India Legalises Interfaith Civil Marriage", place: "New Delhi, India", iso: "IN", lat: 28.61, lng: 77.21, cat: "legal", blurb: "The Special Marriage Act 1954 allowed any two Indian citizens to marry regardless of religion, caste, or creed before a Marriage Officer, without either party needing to convert — the first comprehensive statutory framework on the subcontinent for legally recognised interfaith and inter-caste love marriage.", src: ["Special Marriage Act, Act No. 43 of 1954 (India)","Agnes, F. Family Law Vol. I (2011)"] },
  { id: "india-hindu-marriage-act-1955", year: 1955, title: "India's Hindu Marriage Act permits divorce", place: "New Delhi, India", iso: "IN", lat: 28.6139, lng: 77.209, cat: "legal", blurb: "The Hindu Marriage Act 1955 introduced statutory divorce for the first time in India, replacing the classical Hindu rule of marriage as an indissoluble sacrament — but only on fault grounds (adultery, cruelty, desertion). Mutual-consent divorce was added only in 1976, and personal laws for Muslims, Christians, and Parsis have remained separately governed.", src: ["Hindu Marriage Act 1955, Act No. 25 of 1955","Flavia Agnes, Family Law (2011)"] },
  { id: "tunisia-1956", year: 1956, title: "Tunisia bans polygamy", place: "Tunisia", iso: "TN", lat: 36.8, lng: 10.18, cat: "polygamy", blurb: "Tunisia’s Code of Personal Status outlaws polygamy and unilateral male divorce — among the most progressive in the Arab world.", src: ["Code of Personal Status 1956"] },
  { id: "iraq-personal-status-1959", year: 1959, title: "Iraq severely restricts polygamy by law", place: "Baghdad, Iraq", iso: "IQ", lat: 33.34, lng: 44.4, cat: "legal", blurb: "Iraq's Personal Status Law No. 188 (1959) required court permission for a second marriage and mandated proof that the husband could treat wives equally and had just cause — one of the most restrictive polygamy laws in the Arab world at the time.", src: ["Iraqi Personal Status Law No. 188 (1959)","Al-Azmeh, A. — Islam and Modernities (1993)"] },
  { id: "india-dowry-prohibition-act", year: 1961, title: "India Bans Giving and Taking Dowry", place: "New Delhi, India", iso: "IN", lat: 28.6139, lng: 77.209, cat: "custom", blurb: "India's Dowry Prohibition Act of 1961 was the first comprehensive national law to make both the giving and receiving of dowry a criminal offence across all religions, responding to the epidemic of 'dowry deaths'. Though enforcement remained challenging and the Act was strengthened by amendments in 1984, it established the global template for anti-dowry legislation.", src: ["https://www.britannica.com/event/Dowry-Prohibition-Act","https://www.indiacode.nic.in/handle/123456789/1679"] },
  { id: "un-consent", year: 1962, title: "UN consent & minimum-age convention", place: "New York", iso: "US", lat: 40.75, lng: -73.97, cat: "age", blurb: "The UN Convention on Consent to Marriage sets global norms requiring free consent and a minimum age to marry.", src: ["UN 1962"] },
  { id: "un-convention-consent-1962", year: 1962, title: "UN treaty mandates minimum marriage age", place: "New York, USA", iso: "US", lat: 40.75, lng: -73.98, cat: "legal", blurb: "The Convention on Consent to Marriage, Minimum Age for Marriage and Registration of Marriages (1962) was the first binding international treaty requiring state parties to set a statutory minimum age and ensure free consent. It obligated registering all marriages, a key anti-child-marriage enforcement tool.", src: ["UN Convention on Consent to Marriage, 1962 (UNGA Res. 1763 XVII)","Cook, R. (1994). Human Rights of Women."] },
  { id: "loving", year: 1967, title: "Interracial marriage legalised (US)", place: "United States", iso: "US", lat: 37.5, lng: -77.4, cat: "rights", blurb: "Loving v. Virginia strikes down US bans on interracial marriage, affirming marriage as a civil right.", src: ["Loving v. Virginia"] },
  { id: "loving-v-virginia", year: 1967, title: "US Supreme Court strikes anti-miscegenation bans", place: "Washington D.C., USA", iso: "US", lat: 38.9, lng: -77.04, cat: "rights", blurb: "In Loving v. Virginia (12 June 1967), the US Supreme Court unanimously struck down Virginia's ban on interracial marriage as unconstitutional, voiding anti-miscegenation statutes in 16 states. The ruling established that marriage licenses must be available regardless of race under the 14th Amendment's due process and equal protection clauses.", src: ["https://en.wikipedia.org/wiki/Loving_v._Virginia","https://www.britannica.com/event/Loving-v-Virginia"] },
  { id: "california-nofault", year: 1969, title: "Modern no-fault divorce", place: "California, USA", iso: "US", lat: 38.58, lng: -121.49, cat: "divorce", blurb: "California’s reform launches the modern no-fault divorce era that spreads across the Western world.", src: ["Family Law Act 1969"] },
  { id: "california-no-fault-divorce", year: 1969, title: "California Invents No-Fault Divorce", place: "Sacramento, California, USA", iso: "US", lat: 38.5816, lng: -121.4944, cat: "divorce", blurb: "California's Family Law Act of 1969 — signed by Governor Ronald Reagan — created the world's first no-fault divorce law, allowing either spouse to end a marriage on grounds of 'irreconcilable differences' without proving fault. This fundamentally shifted power in marriage exit toward women, who had historically struggled to meet fault-based grounds; it became the global template for modern divorce law.", src: ["https://www.mcfarlinglaw.com/blog/usa-divorce-laws-history/","https://sasforwomen.com/divorce-laws-in-the-united-states-then-and-now/"] },
  { id: "sweden-raises-age-18-1969", year: 1969, title: "Sweden sets 18 as the marriage minimum", place: "Stockholm, Sweden", iso: "SE", lat: 59.33, lng: 18.07, cat: "age", blurb: "Sweden's Marriage Code revision of 1969 raised the minimum marriage age to 18 without exception for both sexes, making Sweden among the first countries globally to reach this benchmark with no parental-consent loophole. It set a Nordic model that several countries later followed.", src: ["Swedish Marriage Code (Äktenskapsbalk), SFS 1987:230 (codifying 1969 reform)","Therborn, G. (2004). Between Sex and Power: Family in the World, 1900–2000."] },
  { id: "california-nofault-1969", year: 1969, title: "California pioneers no-fault divorce, USA", place: "Sacramento, California, USA", iso: "US", lat: 38.5767, lng: -121.4934, cat: "divorce", blurb: "California's Family Law Act 1969 (signed by Governor Ronald Reagan) was the first no-fault divorce law in the Western world, replacing fault grounds with \"irreconcilable differences\" and ending the need to prove wrongdoing in court. It triggered a nationwide wave: all 50 US states adopted some form of no-fault divorce by 1985.", src: ["California Family Law Act 1969, Stats. 1969, ch. 1608","Herbert Jacob, Silent Revolution (1988)"] },
  { id: "uk-divorce-reform-1969", year: 1969, title: "England shifts to irretrievable breakdown", place: "London, England", iso: "GB", lat: 51.4994, lng: -0.1248, cat: "legal", blurb: "The Divorce Reform Act 1969 (in force 1971) replaced England and Wales's fault-based system with a single ground — irretrievable breakdown of marriage — evidenced by facts including two years' separation with consent or five years' separation without it. Though not truly no-fault (facts still had to be proved), it dramatically reduced contested divorces.", src: ["Divorce Reform Act 1969, c.55","John Eekelaar, Family Law and Social Policy (1978)"] },
  { id: "no-fault-divorce-california", year: 1969, title: "California Pioneers No-Fault Divorce", place: "Sacramento, California, USA", iso: "US", lat: 38.58, lng: -121.49, cat: "divorce", blurb: "Governor Ronald Reagan signed California's Family Law Act on 4 December 1969, making it the world's first modern no-fault divorce law — spouses could separate without proving fault, fundamentally reframing marriage as a voluntary partnership that either party could exit, a model adopted by every US state and scores of countries within decades.", src: ["California Family Law Act 1969 (Stats. 1969, c. 1608)","Parkman, A. Good Intentions Gone Awry (2000)"] },
  { id: "indonesia-polygamy-restriction", year: 1974, title: "Indonesia restricts polygamy by statute", place: "Jakarta, Indonesia", iso: "ID", lat: -6.21, lng: 106.85, cat: "legal", blurb: "Indonesia's Marriage Law No. 1/1974 imposed strict court-approval conditions on polygamous marriages for the world's largest Muslim-majority nation, requiring proof of wife's consent and financial capacity — a compromise between Islamic tradition and modern rights.", src: ["Indonesian Marriage Law No. 1 (1974)","Butt, S. — Islam, the State and the Constitutional Court in Indonesia (2010)"] },
  { id: "nebraska-marital-rape-us-first", year: 1975, title: "Nebraska Criminalises Marital Rape in US", place: "Lincoln, Nebraska, USA", iso: "US", lat: 40.8136, lng: -96.7026, cat: "rights", blurb: "Nebraska became the first U.S. state to abolish the spousal rape exemption in 1975, making it illegal for a husband to rape his wife — overturning the Hale doctrine (1736) that marriage implied perpetual consent. It took until 1993 for all 50 states to follow, and most imposed lighter penalties for marital versus stranger rape well into the 2000s.", src: ["https://en.wikipedia.org/wiki/Marital_rape_in_the_United_States","https://digitalcommons.unl.edu/cgi/viewcontent.cgi?article=1085&context=historydiss"] },
  { id: "cedaw-1979-marriage-age", year: 1979, title: "CEDAW declares child marriage discriminatory", place: "New York, USA", iso: "US", lat: 40.75, lng: -73.98, cat: "rights", blurb: "The Convention on the Elimination of All Forms of Discrimination Against Women (1979, Art. 16) explicitly required states to set a minimum marriage age and to make the registration of marriages compulsory, framing child marriage squarely as sex discrimination. With 189 state parties it became the most-ratified instrument bearing on the issue.", src: ["CEDAW Art. 16(2), 1979","Freeman, M. (2009). The UN Convention on the Rights of the Child: A Commentary."] },
  { id: "scotland-marital-rape-ruling", year: 1989, title: "Scotland's Court Kills Marital Rape Immunity", place: "Edinburgh, Scotland", iso: "GB", lat: 55.9533, lng: -3.1883, cat: "rights", blurb: "In S. v. H.M. Advocate (1989), the High Court of Justiciary ruled that the long-standing marital rape exemption had no place in modern Scots law, making Scotland the first part of the UK to criminalise marital rape by judicial decision. England and Wales followed by statute in 1991 via R v. R in the House of Lords.", src: ["https://en.wikipedia.org/wiki/Marital_rape","https://www.scotsman.com/news/opinion/columnists/leader-comment-year-when-marital-rape-became-a-crime-will-shock-you-1433055"] },
  { id: "denmark-registered-partnership-1989", year: 1989, title: "World's First Registered Partnership Law", place: "Copenhagen, Denmark", iso: "DK", lat: 55.676, lng: 12.568, cat: "samesex", blurb: "Denmark became the first country in the world to grant same-sex couples legal recognition through its Registered Partnership Act, effective 1 October 1989, giving nearly all the rights of marriage under Danish law. Axel and Eigil Axgil were the first couple to register.", src: ["Lov om registreret partnerskab, Denmark 1989","Harvard Law Review, 'Same-Sex Partnerships in Europe'"] },
  { id: "marital-rape", year: 1991, title: "Marital rape criminalised (UK)", place: "United Kingdom", iso: "GB", lat: 51.5, lng: -0.12, cat: "rights", blurb: "UK courts end the marital-rape exemption (R v R); many countries follow, recognising that consent applies within marriage.", src: ["R v R 1991"] },
  { id: "norway-registered-partnership-1993", year: 1993, title: "Norway Enacts Partnership Rights", place: "Oslo, Norway", iso: "NO", lat: 59.913, lng: 10.752, cat: "samesex", blurb: "Norway became the second country to legalise registered partnerships for same-sex couples, following Denmark's model closely and granting equivalent civil rights. Sweden followed in 1994, creating a Nordic bloc of recognition.", src: ["Norwegian Registered Partnership Act 1993","Eskridge, William: 'Equality Practice' (2002)"] },
  { id: "hawaii-supreme-court-baehr-1993", year: 1993, title: "Hawaii Court Opens Marriage Debate", place: "Honolulu, Hawaii, USA", iso: "US", lat: 21.306, lng: -157.858, cat: "samesex", blurb: "In Baehr v. Lewin the Hawaii Supreme Court ruled that denying marriage licenses to same-sex couples was presumptive sex discrimination under the state constitution, triggering the first major legal battle over same-sex marriage and sparking defensive legislation across the US.", src: ["Baehr v. Lewin, 74 Haw. 645 (1993)","Pinello, Daniel: 'America's Struggle for Same-Sex Marriage' (2006)"] },
  { id: "ireland-divorce-referendum-1995", year: 1995, title: "Ireland legalises divorce by referendum", place: "Dublin, Ireland", iso: "IE", lat: 53.3498, lng: -6.2603, cat: "legal", blurb: "Ireland's Fifteenth Amendment referendum (November 1995, passed by just 0.6%) removed the constitutional prohibition on divorce, making Ireland one of the last Western countries to legalise it. The Family Law (Divorce) Act 1996 required four years' separation, reflecting the electorate's cautious mandate.", src: ["Fifteenth Amendment of the Constitution Act 1995","Brian Girvin, 'The Irish Divorce Referendum 1995', Irish Pol. Stud. (1996)"] },
  { id: "south-africa-constitution-1996", year: 1996, title: "First Constitution Banning Anti-Gay Discrimination", place: "Cape Town, South Africa", iso: "ZA", lat: -33.925, lng: 18.424, cat: "rights", blurb: "South Africa's post-apartheid Constitution, adopted in 1996, became the first in the world to explicitly prohibit discrimination on the basis of sexual orientation. This provision laid the legal groundwork for the country's later recognition of same-sex marriage.", src: ["Constitution of the Republic of South Africa, 1996, Section 9(3)","de Vos, Pierre: 'The Constitution of South Africa' (2014)"] },
  { id: "south-africa-recognition-customary", year: 1998, title: "South Africa legalises customary polygyny", place: "Cape Town, South Africa", iso: "ZA", lat: -33.93, lng: 18.42, cat: "custom", blurb: "The Recognition of Customary Marriages Act (1998) gave full legal standing to polygynous marriages conducted under African customary law, balancing constitutional equality with cultural recognition — a rare post-apartheid legislative acknowledgement of plural marriage.", src: ["Recognition of Customary Marriages Act No. 120 (1998, South Africa)","Himonga, C. — African Customary Law in South Africa (2014)"] },
  { id: "vermont-civil-unions-2000", year: 2000, title: "Vermont Creates Civil Unions in USA", place: "Montpelier, Vermont, USA", iso: "US", lat: 44.26, lng: -72.576, cat: "samesex", blurb: "Vermont became the first US state to legislate civil unions for same-sex couples, following the state Supreme Court's ruling in Baker v. Vermont (1999) that the constitution required equal benefits. It was the most expansive same-sex partnership recognition in the US at the time.", src: ["Baker v. Vermont, 170 Vt. 194 (1999)","Vermont Civil Union Law, Act 91 (2000)"] },
  { id: "netherlands-samesex", year: 2001, title: "First same-sex marriage", place: "Netherlands", iso: "NL", lat: 52.37, lng: 4.9, cat: "samesex", blurb: "The Netherlands becomes the first country to grant full legal marriage to same-sex couples.", src: ["Dutch law 2001"] },
  { id: "netherlands-same-sex-civil-marriage", year: 2001, title: "First legal same-sex civil marriages worldwide", place: "Amsterdam, Netherlands", iso: "NL", lat: 52.37, lng: 4.9, cat: "samesex", blurb: "On 1 April 2001, the Netherlands became the first country in the world to open civil marriage registration to same-sex couples on equal terms, with the first ceremonies performed at midnight in Amsterdam's city hall. The law treated same-sex and opposite-sex marriages identically in all civil respects.", src: ["https://en.wikipedia.org/wiki/Same-sex_marriage_in_the_Netherlands"] },
  { id: "netherlands-full-marriage-2001", year: 2001, title: "Netherlands: World's First Same-Sex Marriage", place: "Amsterdam, Netherlands", iso: "NL", lat: 52.374, lng: 4.899, cat: "samesex", blurb: "On 1 April 2001 the Netherlands became the first country in the world to open civil marriage fully to same-sex couples, with four couples married at midnight by Amsterdam's mayor. The Dutch law granted identical rights and duties to those of opposite-sex marriages.", src: ["Wet openstelling huwelijk, Netherlands 2001","Waaldijk, Kees: 'Small Change: How the Road to Same-Sex Marriage Got Paved in the Netherlands' (2001)"] },
  { id: "netherlands-same-sex-marriage", year: 2001, title: "Netherlands First to Legalise Same-Sex Marriage", place: "Amsterdam, Netherlands", iso: "NL", lat: 52.37, lng: 4.9, cat: "samesex", blurb: "On 1 April 2001 the Netherlands became the first country in the world to open civil marriage to same-sex couples, when four couples married in Amsterdam's city hall at midnight; the Dutch law transformed marriage from an inherently opposite-sex institution and launched a global movement toward marriage equality.", src: ["Dutch Civil Code, Book 1, Article 30 (amended 2001)","Waaldijk, K. 'Small Change' in Wintemute & Andenæs (2001)"] },
  { id: "belgium-marriage-2003", year: 2003, title: "Belgium Legalises Same-Sex Marriage", place: "Brussels, Belgium", iso: "BE", lat: 50.85, lng: 4.35, cat: "samesex", blurb: "Belgium became the second country in the world to open marriage to same-sex couples, enacting legislation in January 2003. Unlike the Dutch law, the original Belgian law initially limited adoption rights, later corrected in 2006.", src: ["Belgian Act on Same-Sex Marriage 2003","Forder, Caroline: 'Belgium: Same-Sex Couples' (2003)"] },
  { id: "spain-express-divorce-2005", year: 2005, title: "Spain introduces mutual-consent express divorce", place: "Madrid, Spain", iso: "ES", lat: 40.4168, lng: -3.7038, cat: "legal", blurb: "Spain's 2005 reform eliminated the prior legal separation requirement and allowed unilateral divorce with no fault grounds after just three months of marriage — making it one of Europe's most accessible divorce regimes within the EU. The law also extended marriage and adoption rights to same-sex couples in the same legislative package.", src: ["Ley 15/2005, de 8 de julio, BOE-A-2005-11864","Ignacio Sancho Gargallo, Derecho de Familia (2006)"] },
  { id: "canada-marriage-2005", year: 2005, title: "Canada Becomes Third Nation for Marriage Equality", place: "Ottawa, Canada", iso: "CA", lat: 45.421, lng: -75.69, cat: "samesex", blurb: "Canada's Civil Marriage Act (Bill C-38), passed in July 2005, extended marriage to same-sex couples nationwide, making Canada the fourth jurisdiction globally (after Netherlands, Belgium, and Spain, which passed its law weeks earlier). Courts in most provinces had already been performing same-sex marriages since 2003.", src: ["Civil Marriage Act, S.C. 2005, c. 33","Hurley, Mary: 'Same-Sex Marriage: The Legal Landscape' (2005)"] },
  { id: "spain-marriage-2005", year: 2005, title: "Spain Legalises Same-Sex Marriage", place: "Madrid, Spain", iso: "ES", lat: 40.416, lng: -3.703, cat: "samesex", blurb: "Spain's socialist government under Zapatero passed the law legalising same-sex marriage and adoption in June 2005, making Spain the third country globally and the first majority-Catholic nation to do so, despite strong opposition from the Catholic Church.", src: ["Ley 13/2005, España","Encarnación, Omar: 'Spanish Politics: Democracy after Dictatorship' (2008)"] },
  { id: "south-africa-marriage-2006", year: 2006, title: "South Africa: First in Africa for Marriage Equality", place: "Johannesburg, South Africa", iso: "ZA", lat: -26.2, lng: 28.05, cat: "samesex", blurb: "South Africa's Civil Union Act, effective 30 November 2006, made it the first African country — and the fifth globally — to legalise same-sex marriage, following a Constitutional Court ruling in Minister of Home Affairs v. Fourie (2005) that the common-law definition of marriage was unconstitutional.", src: ["Minister of Home Affairs v. Fourie 2006 (1) SA 524 (CC)","South African Civil Union Act 17 of 2006"] },
  { id: "malta-legalises-divorce-2011", year: 2011, title: "Malta: last EU state to allow divorce", place: "Valletta, Malta", iso: "MT", lat: 35.8997, lng: 14.5147, cat: "legal", blurb: "Malta's May 2011 referendum voted 52.7% in favour of legalising divorce, and the Marriage Act Amendment took effect in October 2011 — making Malta the very last country in the European Union (and one of the last in the world) to permit civil divorce. The Catholic Church campaigned strongly against it.", src: ["Malta Marriage Act Amendment, Act XI of 2011","Neil Falzon & Therese Comodini Cachia, Maltese Divorce Referendum Report (2011)"] },
  { id: "niger-highest-child-marriage-rate", year: 2012, title: "Niger recorded world's highest child-marriage rate", place: "Niamey, Niger", iso: "NE", lat: 13.51, lng: 2.11, cat: "age", blurb: "UNICEF's 2012 data showed Niger with the world's highest child-marriage prevalence — 76% of girls married before 18 — despite a nominal legal minimum of 15, highlighting the persistent gap between statute and practice in the Sahel. It became a focal point for global advocacy campaigns.", src: ["UNICEF (2012). Progress for Children: A Report Card on Adolescents.","Girls Not Brides (2014). Child Marriage Around the World: Niger."] },
  { id: "mariage-pour-tous-france", year: 2013, title: "France Legalises Same-Sex Marriage", place: "Paris, France", iso: "FR", lat: 48.85, lng: 2.35, cat: "samesex", blurb: "France's Loi du 17 mai 2013 ouvrant le mariage aux couples de personnes de même sexe — the 'Mariage pour tous' law — extended civil marriage and full adoption rights to same-sex couples, making France the fourteenth country to do so and the largest predominantly Catholic nation to legalise same-sex marriage at that point.", src: ["Loi n° 2013-404 du 17 mai 2013 (France)","Fassin, E. L'inversion de la question homosexuelle (2015)"] },
  { id: "obergefell", year: 2015, title: "US marriage equality", place: "United States", iso: "US", lat: 38.9, lng: -77, cat: "samesex", blurb: "Obergefell v. Hodges legalises same-sex marriage nationwide across the United States.", src: ["Obergefell v. Hodges"] },
  { id: "un-sdg-target-child-marriage-2030", year: 2015, title: "UN sets 2030 goal to end child marriage", place: "New York, USA", iso: "US", lat: 40.75, lng: -73.98, cat: "rights", blurb: "UN Sustainable Development Goal 5.3 (adopted 2015) committed all member states to eliminating child, early and forced marriage by 2030, embedding the issue in the global development agenda for the first time. Progress monitoring via World Bank and UNICEF data thereafter became a formal international accountability mechanism.", src: ["UN General Assembly, Res. 70/1 (2015). Transforming Our World: The 2030 Agenda for Sustainable Development.","UNICEF (2021). Child Marriage: Latest Trends and Future Prospects."] },
  { id: "us-supreme-court-obergefell-2015", year: 2015, title: "US Supreme Court: Marriage Equality Nationwide", place: "Washington DC, USA", iso: "US", lat: 38.897, lng: -77.044, cat: "samesex", blurb: "In Obergefell v. Hodges (26 June 2015) the US Supreme Court ruled 5–4 that the Fourteenth Amendment requires all states to license and recognise same-sex marriages, making marriage equality the law across all 50 states. It was the most consequential same-sex marriage ruling in history by population affected.", src: ["Obergefell v. Hodges, 576 U.S. 644 (2015)"] },
  { id: "obergefell-v-hodges", year: 2015, title: "US Supreme Court Grants Marriage Equality", place: "Washington DC, USA", iso: "US", lat: 38.91, lng: -77.04, cat: "samesex", blurb: "Obergefell v. Hodges (26 June 2015) held 5–4 that the Fourteenth Amendment requires states to license and recognise same-sex marriages, making marriage equality the law in all fifty US states and the District of Columbia — the most sweeping expansion of US marriage rights since Loving v. Virginia.", src: ["Obergefell v. Hodges, 576 U.S. 644 (2015)","Yoshino, K. Speak Now (2015)"] },
  { id: "us-delaware-first-absolute-ban-2016", year: 2016, title: "Delaware first US state to ban all child marriage", place: "Dover, Delaware, USA", iso: "US", lat: 39.16, lng: -75.52, cat: "legal", blurb: "In 2016 Delaware became the first US state to set an absolute minimum marriage age of 18 with no exceptions — eliminating the longstanding judicial or parental-consent bypass that allowed marriages of minors. It sparked a wave of similar legislation across American states.", src: ["Delaware Senate Bill 227 (2016)","Tahirih Justice Center (2017). Falling Through the Cracks: How Laws Allow Child Marriage to Happen in Today's America."] },
  { id: "bangladesh-child-marriage-act-2017", year: 2017, title: "Bangladesh law retains loophole for girls", place: "Dhaka, Bangladesh", iso: "BD", lat: 23.73, lng: 90.4, cat: "legal", blurb: "Bangladesh's Child Marriage Restraint Act 2017 raised the general minimum to 18 for girls and 21 for boys but controversially included an undefined 'special circumstances' clause allowing younger marriages with parental and court consent — widely criticised by rights groups as a regression that perpetuates child marriage.", src: ["Child Marriage Restraint Act 2017 (Bangladesh)","Human Rights Watch (2017). Bangladesh: Child Marriage Law a Dangerous Setback."] },
  { id: "germany-marriage-2017", year: 2017, title: "Germany Opens Marriage to Same-Sex Couples", place: "Berlin, Germany", iso: "DE", lat: 52.52, lng: 13.405, cat: "samesex", blurb: "Germany's Bundestag voted 393–226 on 30 June 2017 to open civil marriage to same-sex couples, twenty-eight years after Denmark's pioneering partnership law. The 'Ehe für alle' ('Marriage for all') bill took effect 1 October 2017.", src: ["Bundesgesetzblatt, Gesetz zur Einführung des Rechts auf Eheschließung für Personen gleichen Geschlechts, 2017"] },
  { id: "massachusetts-raises-age-18-2018", year: 2018, title: "Massachusetts ends child marriage with no exceptions", place: "Boston, Massachusetts, USA", iso: "US", lat: 42.36, lng: -71.06, cat: "age", blurb: "Massachusetts, which had retained a colonial-era minimum of 12 for girls and 14 for boys with judicial consent, enacted a strict 18-year minimum in 2018 — eliminating one of the lowest statutory floors among US states. The reform was notable for closing both the parental and judicial consent loopholes simultaneously.", src: ["Massachusetts Acts 2018, Ch. 148","Unchained At Last (2019). Child Marriage in America: By the Numbers."] },
  { id: "scotland-marriage-minimum-raised-2019", year: 2019, title: "Scotland raises minimum marriage age to 18", place: "Edinburgh, Scotland, UK", iso: "GB", lat: 55.95, lng: -3.19, cat: "age", blurb: "The Marriage (Scotland) Act 2002 amendment, effective June 2019, raised Scotland's minimum marriage age from 16 to 18 and ended the practice that had made Gretna Green famous as a destination for young couples eloping from England. Scotland thereby aligned with the majority of European states.", src: ["Marriage and Civil Partnership (Minimum Age) Act 2019 (Scotland)","Scottish Government (2019). Child Marriage in Scotland: Consultation."] },
  { id: "taiwan-marriage-2019", year: 2019, title: "Taiwan: First in Asia to Legalise", place: "Taipei, Taiwan", iso: "TW", lat: 25.033, lng: 121.565, cat: "samesex", blurb: "Taiwan's Legislative Yuan passed the Enforcement Act for Judicial Yuan Interpretation No. 748 on 17 May 2019, making Taiwan the first jurisdiction in Asia to legalise same-sex marriage, following a 2017 Constitutional Court ruling that the Civil Code's restriction was unconstitutional.", src: ["Judicial Yuan Interpretation No. 748 (2017)","Taiwan Act for Implementation of J.Y. Interpretation No. 748 (2019)"] },
  { id: "costa-rica-marriage-2020", year: 2020, title: "Costa Rica: First in Central America", place: "San José, Costa Rica", iso: "CR", lat: 9.935, lng: -84.084, cat: "samesex", blurb: "Costa Rica became the first Central American country to legalise same-sex marriage on 26 May 2020, the day an Inter-American Court ruling took effect; the first couple married at midnight. The change followed a 2018 Inter-American Court of Human Rights advisory opinion binding on its member states.", src: ["IACHR Advisory Opinion OC-24/17 (2018)","Tico Times, 'Costa Rica becomes first Central American country to allow same-sex marriage' (2020)"] },
  { id: "uk-no-fault-divorce-2022", year: 2022, title: "UK enacts true no-fault divorce", place: "London, England", iso: "GB", lat: 51.4994, lng: -0.1248, cat: "divorce", blurb: "The Divorce, Dissolution and Separation Act 2020 came into force on 6 April 2022, finally abolishing the requirement to prove fault or live apart for years in England and Wales — 53 years after the 1969 Act's half-measure. Either spouse (or both jointly) can now apply for divorce simply by stating the marriage has irretrievably broken down, with no contest possible on the ground itself.", src: ["Divorce, Dissolution and Separation Act 2020, c.11","Resolution, 'No-Fault Divorce: A Guide' (2022)"] },
  { id: "greece-marriage-2024", year: 2024, title: "Greece: First Orthodox Nation for Marriage Equality", place: "Athens, Greece", iso: "GR", lat: 37.983, lng: 23.727, cat: "samesex", blurb: "Greece's parliament voted 176–76 in February 2024 to legalise same-sex civil marriage, making Greece the first majority-Eastern Orthodox Christian country to do so and the 40th country globally to adopt marriage equality.", src: ["Greek Civil Marriage Equality Act 2024","Reuters, 'Greece legalises same-sex marriage' (15 Feb 2024)"] },
];

